import{_ as t,o,c as a,ag as i}from"./chunks/framework.BZohXCq9.js";const s="/homeStore.png",u=JSON.parse('{"title":"🌐 This Website | CoolAid.live 🌐","description":"","frontmatter":{"outline":false},"headers":[],"relativePath":"pages/website.md","filePath":"pages/website.md","lastUpdated":1773600249000}'),r={name:"pages/website.md"};function n(l,e,c,d,h,p){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="🌐-this-website-coolaid-live-🌐" tabindex="-1">🌐 This Website | <a href="https://coolaid.live/" target="_blank" rel="noreferrer">CoolAid.live</a> 🌐 <a class="header-anchor" href="#🌐-this-website-coolaid-live-🌐" aria-label="Permalink to &quot;🌐 This Website | [CoolAid.live](https://coolaid.live/) 🌐&quot;">​</a></h1><h4 id="welcome-to-my-own-static-website-built-using-vitepress" tabindex="-1">Welcome to my own static website built using VitePress! <a class="header-anchor" href="#welcome-to-my-own-static-website-built-using-vitepress" aria-label="Permalink to &quot;Welcome to my own static website built using VitePress!&quot;">​</a></h4><hr><p>This site exists to keep information about myself, my coding projects, and my Twitch community all together in one place. I also just wanted a space separate from the CoolAid Merch store, so I&#39;ve built my own static website with VitePress!</p><p><a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a> is a fast, Vue.js-powered static site generator (SSG) designed for building websites focused on content such as blogs and documentation, for example. It&#39;s built on top of both Vite and Vue, and focuses on performance and simplicity... exactly what I&#39;m looking for in a custom website. For context, <a href="https://vuejs.org/" target="_blank" rel="noreferrer">Vue.js</a> is a JavaScript framework used to build interactive UIs, and <a href="https://vite.dev/" target="_blank" rel="noreferrer">Vite</a> is a dev tool designed to make working on web projects faster by updating code instantly via a local server.</p><p>Pages can be written in markdown (or custom HTML/CSS) and then VitePress converts them into a fully functional static site that can be deployed online. This website runs on GitHub Pages off the repository&#39;s source code</p><table tabindex="0"><thead><tr><th style="text-align:center;">🌐 Also check out the CoolAid48 merch store over at <a href="https://shop.coolaid.live/" target="_blank" rel="noreferrer">shop.coolaid.live</a>, built with Fourthwall 🌐</th></tr></thead><tbody><tr><td style="text-align:center;"><img src="'+s+'" alt="Store Home Page" width="650"></td></tr></tbody></table>',7)])])}const m=t(r,[["render",n]]);export{u as __pageData,m as default};
